from dataclasses import dataclass
from typing import Any

@dataclass
class ValidationResult:
    passed: bool
    violations: list[str]

def validate_delivery(
    records: list[dict[str, Any]],
    contract: DataContract,
) -> ValidationResult:
    """Validate a batch of records against a data contract schema."""
    violations: list[str] = []
    field_map = {f.name: f for f in contract.schema}

    for i, record in enumerate(records):
        # Check for extra fields not in contract (may indicate schema drift)
        extra = set(record.keys()) - set(field_map.keys())
        if extra:
            violations.append(f"Row {i}: unexpected fields {extra}")

        for field_name, spec in field_map.items():
            value = record.get(field_name)

            # Nullability check
            if value is None and not spec.nullable:
                violations.append(f"Row {i}: non-nullable field '{field_name}' is null")
                continue

            # Type check (simplified; production should use Pydantic or similar)
            if value is not None:
                expected_py_type = {
                    'str': str, 'int': int, 'float': (int, float), 'bool': bool
                }.get(spec.dtype)
                if expected_py_type and not isinstance(value, expected_py_type):
                    violations.append(
                        f"Row {i}: '{field_name}' expected {spec.dtype}, "
                        f"got {type(value).__name__}"
                    )

    return ValidationResult(passed=len(violations) == 0, violations=violations)

class ContractRegistry:
    def __init__(self, store):
        # store: a key-value backend (DynamoDB, PostgreSQL, etc.)
        self._store = store

    def register(self, contract: DataContract) -> None:
        """Store a new contract or new version. Raises if version already exists."""
        key = f"{contract.id}:{contract.version}"
        if self._store.exists(key):
            raise ValueError(f"Contract {key} already registered. Use a new version.")
        self._store.put(key, contract)
        # Also update the 'latest' pointer
        self._store.put(f"{contract.id}:latest", contract)

    def get(self, contract_id: str, version: str = "latest") -> DataContract:
        key = f"{contract_id}:{version}"
        result = self._store.get(key)
        if not result:
            raise KeyError(f"Contract not found: {key}")
        return result

    def list_consumer_contracts(self, consumer: str) -> list[DataContract]:
        """Return all latest-version contracts that list this consumer."""
        all_latest = self._store.scan(key_suffix=":latest")
        return [c for c in all_latest if consumer in c.consumers]
